import jakarta.persistence.*;
import org.springframework.data.jpa.repository.JpaRepository;
import org.springframework.stereotype.*;
import org.springframework.transaction.annotation.Transactional;
import java.util.*;

// ── Entity ───────────────────────────────────────────────────────
@Entity
@Table(name = "users")
class User {
    @Id @GeneratedValue(strategy = GenerationType.IDENTITY)
    Long id;
    String name;
    String email;

    @OneToMany(mappedBy = "user", cascade = CascadeType.ALL, fetch = FetchType.LAZY)
    List<Order> orders = new ArrayList<>();

    // constructors, getters, setters
}

@Entity
@Table(name = "orders")
class Order {
    @Id @GeneratedValue(strategy = GenerationType.IDENTITY)
    Long id;
    String product;
    double amount;

    @ManyToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "user_id")
    User user;
}

// ── Repository ───────────────────────────────────────────────────
interface UserRepository extends JpaRepository<User, Long> {}

// ── Service demonstrating lifecycle ──────────────────────────────
@Service
class UserService {
    final UserRepository repo;
    final EntityManager em;
    UserService(UserRepository r, EntityManager em) { repo = r; this.em = em; }

    @Transactional
    public void demonstrateLifecycle() {
        // 1. TRANSIENT — new object, not managed
        User user = new User();
        user.name = "Alice";
        user.email = "alice@example.com";

        // 2. MANAGED — after persist, Hibernate tracks it
        em.persist(user); // or repo.save(user)
        System.out.println("State: MANAGED, id=" + user.id);

        // 3. DIRTY CHECKING — just change the field; Hibernate auto-flushes UPDATE
        user.name = "Alice Smith"; // No explicit save needed!
        // At transaction end: UPDATE users SET name='Alice Smith' WHERE id=?

        // 4. DETACHED — remove from context
        em.detach(user);
        user.name = "Bob"; // NOT tracked — no UPDATE
        System.out.println("State: DETACHED — change NOT persisted");
    }

    @Transactional(readOnly = true)
    public void demonstrateLazy(Long userId) {
        User user = repo.findById(userId).orElseThrow();
        System.out.println("User loaded: " + user.name); // 1 query
        // Orders NOT loaded yet — proxy placeholder
        int size = user.orders.size(); // LAZY TRIGGER — 2nd query here
        System.out.println("Orders loaded on access: " + size);
    }
}

import jakarta.persistence.*;
import org.springframework.data.jpa.repository.*;
import org.springframework.stereotype.*;
import org.springframework.transaction.annotation.Transactional;
import java.util.*;

// Entities same as above (User + Order)

interface OrderRepository extends JpaRepository<Order, Long> {

    // ── N+1 PROBLEM ── (don't do this)
    // List<User> findAll() → for each User, accessing user.orders fires a separate query

    // ── FIX 1: JOIN FETCH in JPQL ──────────────────────────────
    @Query("SELECT DISTINCT u FROM User u LEFT JOIN FETCH u.orders")
    List<User> findAllWithOrders();

    // ── FIX 2: @EntityGraph ────────────────────────────────────
    @EntityGraph(attributePaths = {"orders"})
    List<User> findAllBy(); // all users with orders eagerly loaded

    // ── Pagination ─────────────────────────────────────────────
    @Query("SELECT u FROM User u")
    org.springframework.data.domain.Page<User> findAllPaged(
        org.springframework.data.domain.Pageable pageable);
}

@Service
class ReportService {
    final UserRepository userRepo;
    ReportService(UserRepository r) { userRepo = r; }

    // ── N+1 BAD ─────────────────────────────────────────────────
