    @OneToMany(mappedBy="dept", fetch=FetchType.LAZY) List<Employee> employees = new ArrayList<>();
}
@Entity class Employee {
    @Id @GeneratedValue Long id; String name;
    @ManyToOne @JoinColumn(name="dept_id") Department dept;
}

interface DepartmentRepository extends JpaRepository<Department, Long> {
    // BAD: findAll() + d.employees.size() = 1 + N queries

    // GOOD: one query with JOIN FETCH
    @Query("SELECT DISTINCT d FROM Department d LEFT JOIN FETCH d.employees")
    List<Department> findAllWithEmployees();
}
