import jakarta.persistence.*;

@Entity
public class BankAccount {
    @Id @GeneratedValue Long id;
    String owner;
    double balance;

    @Version // Hibernate adds: WHERE id=? AND version=? to every UPDATE
    Long version;
}

// Scenario (pseudocode):
// Transaction 1: account = find(1); account.balance = 1200; save(); // sets version=1
// Transaction 2: account = find(1); // reads version=0
//                account.balance = 800;
//                save(); // UPDATE ... WHERE id=1 AND version=0 → 0 rows updated
//                        // → throws OptimisticLockException
//
// In Spring: catch OptimisticLockingFailureException, retry or return 409 Conflict to client
//
// vs Pessimistic: @Lock(LockModeType.PESSIMISTIC_WRITE) → SELECT FOR UPDATE (blocks other readers)
// Use optimistic when conflicts are rare; pessimistic when conflicts are frequent
